import React from "react";
import { useNavigate } from "react-router-dom";

function Dashboard() {
  const navigate = useNavigate(); // ✅ INSIDE function

  return (
    <div>
      <h1>Dashboard</h1>

      <button onClick={() => navigate("/products")}>
        Go to Products
      </button>
    </div>
  );
}

export default Dashboard; // ✅ VERY IMPORTANT
